  ('aboriginal-a5729396-moex-00194', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '刑法第135條第4項規定，對於公務員依法執行職務時，施以強暴，因而致公務員於死，係屬下列何種犯 罪類型？', '["身分犯", "不作為犯", "集合犯", "加重結果犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00195', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '依刑法關於責任能力之規定，行為人行為時因精神障礙或其他心智缺陷，致其辨識行為違法或依其辨識而 行為之能力，顯著減低者，其法律效果為何？', '["減輕其刑", "得減輕其刑", "不罰", "免除其刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00196', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲見竊賊乙行竊路邊停放車輛，因警報響起而放棄行竊逃跑，甲仍在後緊追不捨，終於順利逮捕乙。但也 因此導致乙跌倒受傷、身體自由受限。乙提告甲犯傷害罪、妨害自由罪。下列敘述何者正確？', '["乙之竊盜犯行並未既遂，故非現行犯", "甲所為合於刑事訴訟法逮捕現行犯之規定，雖造成乙法益受害，但屬依法令之行為，不罰", "甲所為係屬緊急避難，不罰", "甲所為係屬自助行為，不罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00197', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '通緝犯甲經員警乙、丙2人包圍在甲之住宅內，乙、丙2人一時疏忽沒有留意甲從廁所窗戶跳出而逃逸， 乙、丙之行為如何評價？', '["構成刑法上之便利脫逃罪", "構成刑法上之公務員因過失致職務上依法逮捕拘禁之人脫逃罪", "構成刑法上之公務員圖利罪", "沒有刑責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00198', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何種持有槍枝行為，成立犯罪？', '["鑑識人員持查獲槍枝，鑑定該槍枝有無殺傷力", "檢察官開偵查庭時，持該槍枝供犯罪嫌疑人辨識", "警察查獲槍枝後，未陳報而私藏該槍枝", "書記官於開庭前調取扣案槍枝，準備於開庭時供法官提示調查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00199', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列有關刑法妨害公務罪之敘述，何者錯誤？', '["甲因積欠電費未繳，經電力公司員工乙前往斷電，甲出手毆打乙，甲不構成妨害公務罪", "警員甲因乙涉犯傷害罪，送達通知書至乙家，通知乙到警局製作警詢筆錄時，乙對甲脅迫稱：「你不要 管，否則殺你」，乙係犯妨害公務罪", "甲幫助受逮捕拘禁之乙脫逃，係犯刑法第135條第1項妨害公務罪", "警員甲下班後協助發生車禍之乙、丙商談民事和解，乙因不滿甲所提和解方案，竟出手毆打甲，乙不構 成妨害公務罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00200', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '警員甲經民眾撥打指揮中心電話通報，於某處發生過失傷害之車禍案件，甲於尚不知何人肇事時前往現場， 一抵達現場，肇事者乙立即向甲坦承係其肇事。下列敘述何者正確？', '["乙符合自首要件，應減輕其刑", "乙符合自首要件，得減輕其刑", "乙不符合自首要件", "乙符合自首要件，得免除其刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00201', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族工作權保障法之比例進用規定，各級政府機關、公立學校及公營事業機構，其僱用約僱 人員、駐衛警察、技工、駕駛、工友、清潔工、收費管理員、其他不須具公務人員任用資格之非技術 性工級職務之總額，每滿多少人應有原住民一人？', '["五百人", "三百人", "二百人", "一百人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00202', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族健康法之規定，原住民族地區之公立健康照護機構應優先進用何種健康照護人員，並提 供具文化安全之服務？', '["具原住民身分或熟諳當地族語", "具原住民身分或居住在機構附近", "具原住民身分或有護理師證照者", "具原住民身分或有文化資產守護證照者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00203', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例之規定，下列何者可以向主管機關申請智慧創作之認定與登記？', '["原住民族委員會", "原住民族", "部落", "原住民個人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
